import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"د Cloudflare R2 Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/cloudflare-r2.md","filePath":"ps/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"ps/upload/cloudflare-r2.md"};function c(u,e,s,h,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="د-cloudflare-r2-channel-اضافه-کول" tabindex="-1">د Cloudflare R2 Channel اضافه کول <a class="header-anchor" href="#د-cloudflare-r2-channel-اضافه-کول" aria-label="Permalink to &quot;د Cloudflare R2 Channel اضافه کول&quot;">​</a></h1><h2 id="کله-مناسب-دی" tabindex="-1">کله مناسب دی <a class="header-anchor" href="#کله-مناسب-دی" aria-label="Permalink to &quot;کله مناسب دی&quot;">​</a></h2><p>Cloudflare R2 هغه وخت وکاروئ چې:</p><ul><li>ستاسې ImgBed site لا مخکې په Cloudflare کې deployed وي او files د هماغه Cloudflare account په R2 bucket کې ساتل غواړئ.</li><li>نه غواړئ جلا S3 endpoint، access key او secret key configure کړئ.</li><li>غواړئ reads او writes د Worker یا Pages R2 binding له لارې په لږ setup سره ترسره شي.</li></ul><p>لنډه خبره:</p><p>R2 channel د ImgBed admin panel دننه manual نه جوړېږي. لومړی باید R2 bucket د Cloudflare project سره bind کړئ، او binding variable name باید دقیقاً <code>img_r2</code> وي.</p><h2 id="د-پیل-مخکې-اړتیاوې" tabindex="-1">د پیل مخکې اړتیاوې <a class="header-anchor" href="#د-پیل-مخکې-اړتیاوې" aria-label="Permalink to &quot;د پیل مخکې اړتیاوې&quot;">​</a></h2><ul><li>Cloudflare account.</li><li>یو موجود R2 bucket.</li><li>د هغه Cloudflare project د مدیریت permission چې ImgBed پکې deployed دی.</li></ul><h2 id="په-cloudflare-کې-configure-کول" tabindex="-1">په Cloudflare کې Configure کول <a class="header-anchor" href="#په-cloudflare-کې-configure-کول" aria-label="Permalink to &quot;په Cloudflare کې Configure کول&quot;">​</a></h2><h3 id="_1-r2-bucket-جوړ-کړئ" tabindex="-1">1. R2 Bucket جوړ کړئ <a class="header-anchor" href="#_1-r2-bucket-جوړ-کړئ" aria-label="Permalink to &quot;1. R2 Bucket جوړ کړئ&quot;">​</a></h3><ol><li>Cloudflare Dashboard ته log in شئ.</li><li><code>R2 Object Storage</code> پرانیزئ.</li><li>Create bucket کلیک کړئ.</li><li>bucket name وټاکئ، لکه <code>imgbed</code>.</li></ol><p>uploaded files به په همدې bucket کې ساتل کېږي.</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bucket-د-imgbed-project-سره-bind-کړئ" tabindex="-1">2. Bucket د ImgBed Project سره Bind کړئ <a class="header-anchor" href="#_2-bucket-د-imgbed-project-سره-bind-کړئ" aria-label="Permalink to &quot;2. Bucket د ImgBed Project سره Bind کړئ&quot;">​</a></h3><p>د deployment type له مخې binding location وټاکئ:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>د binding اضافه کولو پر وخت مهم fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>هغه bucket وټاکئ چې جوړ کړی مو دی.</td></tr></tbody></table><p>Variable name باید دقیقاً <code>img_r2</code> وي. د R2 files upload، read او delete ټول په همدې binding name پورې تړلي دي.</p><h3 id="_3-project-بیا-deploy-کړئ" tabindex="-1">3. Project بیا Deploy کړئ <a class="header-anchor" href="#_3-project-بیا-deploy-کړئ" aria-label="Permalink to &quot;3. Project بیا Deploy کړئ&quot;">​</a></h3><p>د binding له save وروسته ImgBed redeploy کړئ، څو Worker یا Pages runtime <code>img_r2</code> ته access ولري.</p><h2 id="په-imgbed-کې-به-څه-ووینئ" tabindex="-1">په ImgBed کې به څه ووینئ <a class="header-anchor" href="#په-imgbed-کې-به-څه-ووینئ" aria-label="Permalink to &quot;په ImgBed کې به څه ووینئ&quot;">​</a></h2><p>کله چې R2 binding available شي، دا پرانیزئ:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li><code>Cloudflare R2</code> channel.</li></ol><p>system په اتومات ډول یو fixed channel جوړوي:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>دا fixed binding channel دی. د جوړولو لپاره Add Channel ته اړتیا نشته، او د regular channel په څېر delete کېدای نه شي.</p><h2 id="په-admin-panel-کې-editable-fields" tabindex="-1">په Admin Panel کې Editable Fields <a class="header-anchor" href="#په-admin-panel-کې-editable-fields" aria-label="Permalink to &quot;په Admin Panel کې Editable Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>څه کوي</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>کنټرولوي چې R2 په upload selection کې ګډون وکړي که نه.</td><td>Yes</td></tr><tr><td>Account ID</td><td>یوازې هغه وخت کارېږي چې quota limits enabled وي او official R2 usage query پکار وي.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>یوازې هغه وخت کارېږي چې quota limits enabled وي او official R2 usage query پکار وي.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>کنټرولوي چې دا R2 channel د capacity له مخې په upload selection کې ګډون وکړي که نه.</td><td>No</td></tr><tr><td>Threshold</td><td>کله چې usage ټاکلي percentage ته ورسېږي، په دې channel کې write بندوي.</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>Account ID د Cloudflare dashboard د account information panel څخه copy کولی شئ. یوازې هغه وخت یې ډک کړئ چې غواړئ ImgBed R2 quota usage query او enforce کړي.</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>په Cloudflare کې R2 bucket جوړ کړئ.</li><li>د ImgBed project لپاره Cloudflare settings پرانیزئ.</li><li>R2 bucket binding اضافه کړئ.</li><li><code>Variable name</code> ته <code>img_r2</code> ورکړئ.</li><li>هغه R2 bucket وټاکئ چې جوړ کړی مو دی.</li><li>binding save کړئ او ImgBed redeploy کړئ.</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings ته بېرته ولاړ شئ.</li><li>وګورئ چې <code>Cloudflare R2</code> channel ښکاري او enabled دی.</li></ol><p>که غواړئ R2 د capacity له مخې upload selection کې ګډون وکړي، quota limit enable کړئ، بیا Account ID، bucket name، quota limit او threshold ولیکئ او save یې کړئ.</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="څنګه-یې-verify-کړو" tabindex="-1">څنګه یې Verify کړو <a class="header-anchor" href="#څنګه-یې-verify-کړو" aria-label="Permalink to &quot;څنګه یې Verify کړو&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel په Upload Settings کې ښکاري.</li><li>channel card ښيي چې enabled دی.</li><li>یو کوچنی test file upload شي او returned link عادي پرانستل شي.</li><li>که د file پرانیستلو پر وخت <code>R2 database binding is not configured</code> راشي، runtime ته <code>img_r2</code> binding نه دی رسېدلی. په Cloudflare کې binding name وګورئ او project redeploy کړئ.</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
